        let variant: Int32 = try readInt(&buf)
        switch variant {




        case 1: return .LockPoisoned(
            message: try FfiConverterString.read(from: &buf)
        )

        case 2: return .MonitoringError(
            message: try FfiConverterString.read(from: &buf)
        )

        case 3: return .ProcessError(
            message: try FfiConverterString.read(from: &buf)
        )

        case 4: return .CaptureError(
            message: try FfiConverterString.read(from: &buf)
        )

